class Solution {
    public int longestPalindrome(String s, String t) {
        int m = s.length(), n = t.length();
        String st = s + t;
        int len = m + n;
        int[][] dp = new int[len][len];
        int maxLen = 0;
        for (int i = 0; i < len; i++) {
            dp[i][i] = 1;
            maxLen = 1;
        }
        for (int i = len - 1; i >= 0; i--) {
            for (int j = i + 1; j < len; j++) {
                if (st.charAt(i) == st.charAt(j)) {
                    dp[i][j] = j - i + 1 <= 3 ? j - i + 1 : dp[i + 1][j - 1] + 2;
                    if (i < m && j >= m) maxLen = Math.max(maxLen, dp[i][j]);
                } else {
                    dp[i][j] = 0;
                }
            }
        }
        return maxLen;
    }
}
